content:
{
  "sentences": [
    {
      "text": "我想約你一起去喝咖啡。",
      "pinyin": "Wǒ xiǎng yuē nǐ yīqǐ qù hē kāfēi.",
      "pinyin_numeric": "wo3 xiang3 yue1 ni3 yi1qi3 qu4 he1 ka1fei1",
      "translation_en": "I want to invite you to go drink coffee together.",
      "translation_ko": "당신과 함께 커피를 마시러 가고 싶어요."
    },
    {
      "text": "你想跟我一起去看電影嗎？",
      "pinyin": "Nǐ xiǎng gēn wǒ yīqǐ qù kàn diànyǐng ma?",
      "pinyin_numeric": "ni3 xiang3 gen1 wo3 yi1qi3 qu4 kan4 dian4ying3 ma0",
      "translation_en": "Do you want to go watch a movie with me?",
      "translation_ko": "저랑 같이 영화 보러 가고 싶어요?"
    },
    {
      "text": "他想要約朋友一起去吃飯。",
      "pinyin": "Tā xiǎng yào yuē péngyǒu yīqǐ qù chīfàn.",
      "pinyin_numeric": "ta1 xiang3 yao4 yue1 peng2you3 yi1qi3 qu4 chi1fan4",
      "translation_en": "He wants to invite friends to go eat together.",
      "translation_ko": "그는 친구들과 함께 밥을 먹으러 가고 싶어 해요."
    },
    {
      "text": "我們想約時間見面聊天。",
      "pinyin": "Wǒmen xiǎng yuē shíjiān jiànmiàn liáotiān.",
      "pinyin_numeric": "wo3men xiang3 yue1 shi2jian1 jian4mian4 liao2tian1",
      "translation_en": "We want to arrange a time to meet and chat.",
      "translation_ko": "우리는 시간을 정해서 만나서 이야기하고 싶어요."
    },
    {
      "text": "你想去哪裡逛街？",
      "pinyin": "Nǐ xiǎng qù nǎlǐ guàngjiē?",
      "pinyin_numeric": "ni3 xiang3 qu4 na3li3 guang4jie1",
      "translation_en": "Where do you want to go shopping?",
      "translation_ko": "어디로 쇼핑하러 가고 싶어요?"
    },
    {
      "text": "她不想取消約會，可是沒辦法。",
      "pinyin": "Tā bù xiǎng qǔxiāo yuēhuì, kěshì méi bànfǎ.",
      "pinyin_numeric": "ta1 bu4 xiang3 qu3xiao1 yue1hui4, ke3shi4 mei2 ban4fa3",
      "translation_en": "She doesn't want to cancel the date, but there's no choice.",
      "translation_ko": "그녀는 약속을 취소하고 싶지 않지만, 어쩔 수 없어요."
    },
    {
      "text": "我們想提早見面，可以嗎？",
      "pinyin": "Wǒmen xiǎng tízǎo jiànmiàn, kěyǐ ma?",
      "pinyin_numeric": "wo3men xiang3 ti2zao3 jian4mian4, ke3yi3 ma0",
      "translation_en": "We want to meet earlier, is that okay?",
      "translation_ko": "우리는 더 일찍 만나고 싶은데, 괜찮을까요?"
    },
    {
      "text": "你想延後約會的時間嗎？",
      "pinyin": "Nǐ xiǎng yánhòu yuēhuì de shíjiān ma?",
      "pinyin_numeric": "ni3 xiang3 yan2hou4 yue1hui4 de5 shi2jian1 ma0",
      "translation_en": "Do you want to postpone the appointment time?",
      "translation_ko": "약속 시간을 연기하고 싶어요?"
    },
    {
      "text": "他想要準時到咖啡店等我。",
      "pinyin": "Tā xiǎng yào zhǔnshí dào kāfēidiàn děng wǒ.",
      "pinyin_numeric": "ta1 xiang3 yao4 zhun3shi2 dao4 ka1fei1dian4 deng3 wo3",
      "translation_en": "He wants to arrive at the coffee shop on time and wait for me.",
      "translation_ko": "그는 제시간에 커피숍에 도착해서 저를 기다리고 싶어 해요."
    },
    {
      "text": "我們想約在餐廳門口碰面。",
      "pinyin": "Wǒmen xiǎng yuē zài cāntīng ménkǒu pèngmiàn.",
      "pinyin_numeric": "wo3men xiang3 yue1 zai4 can1ting1 men2kou3 peng4mian4",
      "translation_en": "We want to arrange to meet at the restaurant entrance.",
      "translation_ko": "우리는 식당 입구에서 만나기로 하고 싶어요."
    }
  ]
}
